  1→import { Fragment, useEffect, useMemo, useRef, useState } from 'react';
  2→import { Message, StreamSource, TodoItem } from '@/types';
  3→import {
  4→  EVENT_ASSISTANT,
  5→  EVENT_AGENT_END,
  6→  EVENT_ASSISTANT_END,
  7→  EVENT_TOOL_INPUT,
  8→  EVENT_TOOL_OUTPUT,
  9→  EVENT_TODO_UPDATE
 10→} from '@/lib/const';
 11→import { MessageItem } from './MessageItem';
 12→import { Avatar, AvatarFallback } from '@/components/ui/avatar';
 13→import { Bot, Check, ChevronRight, Circle, Loader2, User } from 'lucide-react';
 14→import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
 15→import {
 16→  buildAssistantDisplayItems,
 17→  buildToolDisplayItems,
 18→  type AssistantDisplayItem,
 19→  type ToolDisplayItem,
 20→} from './messageDisplay';
 21→import { extractSingleLinePreview, isToolCallStep } from '@/lib/chatUtils';
 22→import { ThinkingText } from './ThinkingText';
 23→import { cn } from '@/lib/utils';
 24→import { buildSubagentDisplayState } from './subagentGroup';
 25→
 26→interface MessageListProps {
 27→  messages: Message[];
 28→  isLoading: boolean;
 29→  onAskUserSubmit: (interruptId: string | undefined, values: string | Record<string, unknown>) => Promise<void>;
 30→  scrollRef: React.RefObject<HTMLDivElement>;
 31→  selectedDetailMessageId?: string;
 32→  selectedSubagentKey?: string;
 33→  onSelectToolDetail?: (messageId: string) => void;
 34→  onSelectSubagent?: (subagentKey: string) => void;
 35→}
 36→
 37→function SubagentPreviewText({
 38→  text,
 39→  enableTooltip,
 40→  className,
 41→}: {
 42→  text: string;
 43→  enableTooltip: boolean;
 44→  className?: string;
 45→}) {
 46→  const textRef = useRef<HTMLDivElement>(null);
 47→  const [isOverflowing, setIsOverflowing] = useState(false);
 48→
 49→  useEffect(() => {
 50→    if (!enableTooltip) {
 51→      setIsOverflowing(false);
 52→      return;
 53→    }
 54→
 55→    const element = textRef.current;
 56→    if (!element) {
 57→      return;
 58→    }
 59→
 60→    const checkOverflow = () => {
 61→      setIsOverflowing(element.scrollWidth > element.clientWidth);
 62→    };
 63→
 64→    checkOverflow();
 65→
 66→    if (typeof ResizeObserver !== 'undefined') {
 67→      const observer = new ResizeObserver(checkOverflow);
 68→      observer.observe(element);
 69→      return () => observer.disconnect();
 70→    }
 71→
 72→    window.addEventListener('resize', checkOverflow);
 73→    return () => window.removeEventListener('resize', checkOverflow);
 74→  }, [enableTooltip, text]);
 75→
 76→  const content = (
 77→    <div ref={textRef} className={className}>
 78→      {text}
 79→    </div>
 80→  );
 81→
 82→  if (!enableTooltip || !isOverflowing) {
 83→    return content;
 84→  }
 85→
 86→  return (
 87→    <TooltipProvider delayDuration={150}>
 88→      <Tooltip>
 89→        <TooltipTrigger asChild>{content}</TooltipTrigger>
 90→        <TooltipContent side="top" align="start" className="max-w-sm p-3">
 91→          <div className="whitespace-pre-wrap break-words text-xs leading-5">{text}</div>
 92→        </TooltipContent>
 93→      </Tooltip>
 94→    </TooltipProvider>
 95→  );
 96→}
 97→
 98→type MessageBlock =
 99→  | { type: 'user'; message: Message }
100→  | { type: 'assistant'; messages: Message[] };
101→
102→type AssistantContentItem =
103→  | { type: 'main'; key: string; messages: Message[] }
104→  | { type: 'subagent'; key: string; source: StreamSource; messages: Message[] };
105→
106→type AssistantContentView =
107→  | { type: 'main'; key: string; items: AssistantDisplayItem[] }
108→  | {
109→      type: 'subagent';
110→      key: string;
111→      label: string;
112→      preview: string;
113→      taskDescription?: string;
114→      latestAssistantContent?: string;
115→      completed: boolean;
116→      error?: boolean;
117→      isActive: boolean;
118→      todos: TodoItem[];
119→      showTodoPanel: boolean;
120→      items: ToolDisplayItem[];
121→      tokenUsage?: { inputTokens: number; outputTokens: number; totalTokens: number };
122→    };
123→
124→const USER_AVATAR_CLASSNAME =
125→  'absolute right-0 top-0 h-8 w-8 border bg-primary text-primary-foreground shadow-sm';
126→
127→const ASSISTANT_AVATAR_CLASSNAME =
128→  'absolute left-0 top-0 h-8 w-8 border bg-muted shadow-sm';
129→
130→function getThinkingSummary(messages: Message[]): string {
131→  for (let index = messages.length - 1; index >= 0; index -= 1) {
132→    const message = messages[index];
133→    if (!message) continue;
134→
135→    if (typeof message.thinking === 'string') {
136→      const thinkingPreview = extractSingleLinePreview(message.thinking, 36);
137→      if (thinkingPreview) return thinkingPreview;
138→    }
139→
140→    if (message.event === EVENT_ASSISTANT) {
141→      const assistantPreview = extractSingleLinePreview(message.content, 36);
142→      if (assistantPreview) return assistantPreview;
143→    }
144→
145→    if (isToolCallStep(message.event)) {
146→      return `调用工具: ${message.toolName || 'tool'}`;
147→    }
148→
149→    if (message.event === EVENT_TOOL_OUTPUT) {
150→      return `收到工具结果: ${message.toolName || 'tool'}`;
151→    }
152→  }
153→
154→  return '思考中...';
155→}
156→
157→function getMessageSource(message: Message): StreamSource {
158→  return message.source || { kind: 'main', key: 'main', label: message.node };
159→}
160→
161→export function getAssistantContentRenderKey(contentViewKey: string, itemKey: string): string {
162→  return `${contentViewKey}:${itemKey}`;
163→}
164→
165→function isHiddenSubagentItem(item: ReturnType<typeof buildToolDisplayItems>[number]): boolean {
166→  if (item.type === 'tool-pair') {
167→    return (
168→      item.primary.toolName === 'task' ||
169→      item.secondary.toolName === 'task' ||
170→      item.primary.event === EVENT_TODO_UPDATE ||
171→      item.secondary.event === EVENT_TODO_UPDATE ||
172→      item.primary.event === EVENT_AGENT_END ||
173→      item.secondary.event === EVENT_AGENT_END ||
174→      item.primary.event === EVENT_ASSISTANT_END ||
175→      item.secondary.event === EVENT_ASSISTANT_END
176→    );
177→  }
178→
179→  return (
180→    item.message.toolName === 'task' ||
181→    item.message.event === EVENT_TODO_UPDATE ||
182→    item.message.event === EVENT_AGENT_END ||
183→    item.message.event === EVENT_ASSISTANT_END
184→  );
185→}
186→
187→function buildBlocks(messages: Message[]): MessageBlock[] {
188→  const blocks: MessageBlock[] = [];
189→  let currentAssistantBlock: Message[] = [];
190→
191→  const flushAssistantBlock = () => {
192→    if (currentAssistantBlock.length === 0) return;
193→    blocks.push({ type: 'assistant', messages: currentAssistantBlock });
194→    currentAssistantBlock = [];
195→  };
196→
197→  for (const message of messages) {
198→    if (message.role === 'user') {
199→      flushAssistantBlock();
200→      blocks.push({ type: 'user', message });
201→      continue;
202→    }
203→    currentAssistantBlock.push(message);
204→  }
205→
206→  flushAssistantBlock();
207→  return blocks;
208→}
209→
210→function buildAssistantContentItems(messages: Message[]): AssistantContentItem[] {
211→  const items: AssistantContentItem[] = [];
212→  let currentMainMessages: Message[] = [];
213→  const subagentItemsByKey = new Map<string, AssistantContentItem>();
214→
215→  const flushMainMessages = () => {
216→    if (currentMainMessages.length === 0) return;
217→    items.push({
218→      type: 'main',
219→      key: `main-${items.length}`,
220→      messages: currentMainMessages,
221→    });
222→    currentMainMessages = [];
223→  };
224→
225→  for (const message of messages) {
226→    const source = getMessageSource(message);
227→    if (source.kind !== 'subagent') {
228→      currentMainMessages.push(message);
229→      continue;
230→    }
231→
232→    flushMainMessages();
233→    const existing = subagentItemsByKey.get(source.key);
234→    if (existing && existing.type === 'subagent') {
235→      existing.messages.push(message);
236→      continue;
237→    }
238→
239→    const item: AssistantContentItem = {
240→      type: 'subagent',
241→      key: source.key,
242→      source,
243→      messages: [message],
244→    };
245→    subagentItemsByKey.set(source.key, item);
246→    items.push(item);
247→  }
248→
249→  flushMainMessages();
250→  return items;
251→}
252→
253→// 先把原始消息整理成”主 assistant 内容 / subagent 卡片”两类视图模型，
254→// 渲染层只消费这个中间结构，避免 JSX 里反复推导状态。
255→function buildAssistantContentViews(
256→  messages: Message[],
257→  streamingMessageId?: string,
258→  activeMessageId?: string,
259→) {
260→  const contentItems = buildAssistantContentItems(messages);
261→  const contentViews = contentItems.map<AssistantContentView>(contentItem => {
262→    if (contentItem.type === 'subagent') {
263→      const displayState = buildSubagentDisplayState({
264→        key: contentItem.key,
265→        label: contentItem.source.label || 'Subagent',
266→        messages: contentItem.messages,
267→      });
268→
269→      // A subagent is active if the last overall assistant message belongs to it
270→      const isActive = Boolean(
271→        activeMessageId && contentItem.messages.some(message => message.id === activeMessageId),
272→      );
273→
274→      // Extract the latest token usage from subagent assistant-end messages
275→      let subagentTokenUsage: { inputTokens: number; outputTokens: number; totalTokens: number } | undefined;
276→      for (let i = contentItem.messages.length - 1; i >= 0; i--) {
277→        if (contentItem.messages[i].tokenUsage) {
278→          subagentTokenUsage = contentItem.messages[i].tokenUsage;
279→          break;
280→        }
281→      }
282→
283→      return {
284→        type: 'subagent',
285→        key: displayState.key,
286→        label: displayState.label,
287→        preview: displayState.preview,
288→        taskDescription: displayState.taskDescription,
289→        latestAssistantContent: displayState.latestAssistantContent,
290→        completed: displayState.completed,
291→        error: displayState.error,
292→        isActive,
293→        todos: displayState.todos,
294→        showTodoPanel: displayState.showTodoPanel,
295→        items: buildToolDisplayItems(contentItem.messages).filter(item => !isHiddenSubagentItem(item)),
296→        tokenUsage: subagentTokenUsage,
297→      };
298→    }
299→
300→    return {
301→      type: 'main',
302→      key: contentItem.key,
303→      items: buildAssistantDisplayItems(contentItem.messages, streamingMessageId),
304→    };
305→  });
306→
307→  return contentViews;
308→}
309→
310→interface MessageRenderCallbacks {
311→  isLoading: boolean;
312→  selectedDetailMessageId?: string;
313→  selectedSubagentKey?: string;
314→  onAskUserSubmit: (interruptId: string | undefined, values: string | Record<string, unknown>) => Promise<void>;
315→  onSelectToolDetail?: (messageId: string) => void;
316→  onSelectSubagent?: (subagentKey: string) => void;
317→}
318→
319→function renderToolDisplayItem(
320→  item: ToolDisplayItem,
321→  streamingMessageId: string | undefined,
322→  callbacks: MessageRenderCallbacks,
323→  options?: { displayVariant?: 'default' | 'thinking'; thinkingDisplayMode?: 'collapsible' | 'inline' },
324→) {
325→  if (item.type === 'tool-pair') {
326→    return (
327→      <MessageItem
328→        key={item.key}
329→        message={item.primary}
330→        secondaryMessage={item.secondary}
331→        isLoading={callbacks.isLoading}
332→        isStreaming={item.primary.id === streamingMessageId || item.secondary.id === streamingMessageId}
333→        displayVariant={options?.displayVariant}
334→        thinkingDisplayMode={options?.thinkingDisplayMode}
335→        isSelected={item.primary.id === callbacks.selectedDetailMessageId}
336→        onAskUserSubmit={callbacks.onAskUserSubmit}
337→        onSelectToolDetail={callbacks.onSelectToolDetail}
338→      />
339→    );
340→  }
341→
342→  return (
343→    <MessageItem
344→      key={item.key}
345→      message={item.message}
346→      isLoading={callbacks.isLoading}
347→      isStreaming={item.message.id === streamingMessageId}
348→      displayVariant={options?.displayVariant}
349→      thinkingDisplayMode={options?.thinkingDisplayMode}
350→      isSelected={item.message.id === callbacks.selectedDetailMessageId}
351→      onAskUserSubmit={callbacks.onAskUserSubmit}
352→      onSelectToolDetail={callbacks.onSelectToolDetail}
353→    />
354→  );
355→}
356→
357→function renderThinkingGroup(
358→  item: Extract<AssistantDisplayItem, { type: 'thinking-group' }>,
359→  callbacks: MessageRenderCallbacks,
360→) {
361→  const thinkingGroupStreamingId = item.streamingMessageId;
362→  const summaryPreview = getThinkingSummary(item.messages);
363→
364→  return (
365→    <details
366→      key={item.key}
367→      className="group min-w-0 overflow-hidden rounded-lg border border-border/70 bg-muted/30 px-3 py-2"
368→    >
369→      <summary className="flex cursor-pointer list-none items-center gap-1.5 text-xs font-medium text-muted-foreground [&::-webkit-details-marker]:hidden">
370→        <ChevronRight className="h-3.5 w-3.5 shrink-0 transition-transform duration-200 group-open:rotate-90" />
371→        <span
372→          className={cn(
373→            'group-open:hidden truncate',
374→            thinkingGroupStreamingId && 'animate-pulse',
375→          )}
376→        >
377→          {summaryPreview}
378→        </span>
379→        <span className="hidden group-open:inline">思考过程</span>
380→      </summary>
381→      <div className="mt-2 min-w-0 space-y-2 overflow-hidden">
382→        {buildToolDisplayItems(item.messages).map(thinkingItem => {
383→          if (thinkingItem.type === 'tool-pair') {
384→            return renderToolDisplayItem(thinkingItem, thinkingGroupStreamingId, callbacks, {
385→              displayVariant: 'thinking',
386→            });
387→          }
388→
389→          const isSingleToolMessage =
390→            isToolCallStep(thinkingItem.message.event) ||
391→            thinkingItem.message.event === EVENT_TOOL_OUTPUT;
392→
393→          if (isSingleToolMessage) {
394→            return renderToolDisplayItem(thinkingItem, thinkingGroupStreamingId, callbacks, {
395→              displayVariant: 'thinking',
396→            });
397→          }
398→
399→          const thinkingText = thinkingItem.message.thinking || thinkingItem.message.content;
400→          if (thinkingText) {
401→            return (
402→              <div
403→                key={`thinking-${thinkingItem.key}`}
404→                className="min-w-0 overflow-hidden text-muted-foreground/75"
405→              >
406→                <ThinkingText content={thinkingText} />
407→              </div>
408→            );
409→          }
410→
411→          return renderToolDisplayItem(thinkingItem, thinkingGroupStreamingId, callbacks, {
412→            displayVariant: 'thinking',
413→          });
414→        })}
415→      </div>
416→    </details>
417→  );
418→}
419→
420→function renderMainContentView(
421→  contentView: Extract<AssistantContentView, { type: 'main' }>,
422→  streamingMessageId: string | undefined,
423→  callbacks: MessageRenderCallbacks,
424→) {
425→  return contentView.items.map(item => {
426→    const renderKey = getAssistantContentRenderKey(contentView.key, item.key);
427→
428→    if (item.type === 'thinking-group') {
429→      return (
430→        <Fragment key={renderKey}>
431→          {renderThinkingGroup(item, callbacks)}
432→        </Fragment>
433→      );
434→    }
435→
436→    if (item.type === 'tool-pair') {
437→      return (
438→        <Fragment key={renderKey}>
439→          <MessageItem
440→            key={item.key}
441→            message={item.primary}
442→            secondaryMessage={item.secondary}
443→            isLoading={callbacks.isLoading}
444→            isStreaming={item.secondary.id === streamingMessageId}
445→            isSelected={item.primary.id === callbacks.selectedDetailMessageId}
446→            onAskUserSubmit={callbacks.onAskUserSubmit}
447→            onSelectToolDetail={callbacks.onSelectToolDetail}
448→          />
449→        </Fragment>
450→      );
451→    }
452→
453→    return (
454→      <Fragment key={renderKey}>
455→        <MessageItem
456→          key={item.key}
457→          message={item.message}
458→          isLoading={callbacks.isLoading}
459→          isStreaming={item.message.id === streamingMessageId && item.message.event !== EVENT_TOOL_INPUT}
460→          isSelected={item.message.id === callbacks.selectedDetailMessageId}
461→          onAskUserSubmit={callbacks.onAskUserSubmit}
462→          onSelectToolDetail={callbacks.onSelectToolDetail}
463→        />
464→      </Fragment>
465→    );
466→  });
467→}
468→
469→function renderTodoStatusIcon(status: TodoItem['status']) {
470→  if (status === 'completed') {
471→    return (
472→      <span className="flex h-4 w-4 items-center justify-center rounded-full bg-foreground text-background">
473→        <Check className="h-2.5 w-2.5" strokeWidth={3} />
474→      </span>
475→    );
476→  }
477→
478→  if (status === 'in_progress') {
479→    return <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />;
480→  }
481→
482→  return <Circle className="h-4 w-4 text-muted-foreground" />;
483→}
484→
485→function renderSubagentTodoList(
486→  keyPrefix: string,
487→  todos: TodoItem[],
488→  contentClassName: string,
489→) {
490→  return (
491→    <ol className="space-y-2">
492→      {todos.map((todo, index) => (
493→        <li key={`${keyPrefix}-${todo.content}-${index}`} className="flex items-start gap-2 text-xs">
494→          <span className="mt-[2px] shrink-0">{renderTodoStatusIcon(todo.status)}</span>
495→          <span className="text-muted-foreground tabular-nums">{index + 1}.</span>
496→          <span
497→            className={cn(
498→              'min-w-0 flex-1 leading-5',
499→              contentClassName,
500→              todo.status === 'completed' && 'text-muted-foreground line-through',
501→            )}
502→          >
503→            {todo.content}
504→          </span>
505→        </li>
506→      ))}
507→    </ol>
508→  );
509→}
510→
511→function renderSubagentContentView(
512→  contentView: Extract<AssistantContentView, { type: 'subagent' }>,
513→  callbacks: MessageRenderCallbacks,
514→) {
515→  const isSelected = callbacks.selectedSubagentKey === contentView.key;
516→  const labelContent = (
517→    <div className="min-w-0 flex-1">
518→      <div className="truncate text-sm font-semibold text-foreground">{contentView.label}</div>
519→      <SubagentPreviewText
520→        text={contentView.preview}
521→        enableTooltip={Boolean(contentView.latestAssistantContent && !contentView.completed)}
522→        className={cn(
523→          'truncate text-xs',
524→          contentView.error ? 'text-destructive' : 'text-muted-foreground',
525→          callbacks.isLoading && contentView.isActive && !contentView.completed && !contentView.error && 'animate-pulse',
526→        )}
527→      />
528→    </div>
529→  );
530→
531→  return (
532→    <button
533→      type="button"
534→      key={`subagent-${contentView.key}`}
535→      data-subagent-card={contentView.key}
536→      aria-pressed={isSelected}
537→      onClick={() => callbacks.onSelectSubagent?.(contentView.key)}
538→      className={cn(
539→        'group/subagent relative flex w-full items-center gap-3 overflow-visible rounded-2xl border px-4 py-3 text-left shadow-sm transition-colors',
540→        contentView.error
541→          ? 'border-destructive/40 bg-destructive/5'
542→          : isSelected
543→            ? 'border-primary/40 bg-primary/5'
544→            : 'border-border/60 bg-muted/20 hover:bg-muted/35',
545→      )}
546→    >
547→      <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full border bg-background text-foreground/80 shadow-sm">
548→        <Bot className="h-4 w-4" />
549→      </div>
550→      {labelContent}
551→      {contentView.tokenUsage && (
552→        <span className="shrink-0 text-[11px] text-muted-foreground tabular-nums">
553→          {contentView.tokenUsage.totalTokens.toLocaleString('en-US')} tokens
554→        </span>
555→      )}
556→      <ChevronRight className="h-4 w-4 shrink-0 text-muted-foreground" />
557→
558→      {contentView.showTodoPanel && (
559→        <div className="pointer-events-none absolute left-[calc(100%+0.75rem)] top-0 z-20 w-80 rounded-xl border border-border/70 bg-popover/95 p-3 opacity-0 shadow-xl transition-opacity duration-150 group-hover/subagent:opacity-100">
560→          <div className="mb-2 text-[10px] font-semibold uppercase tracking-[0.16em] text-muted-foreground">
561→            {contentView.label} Todos
