583→function AssistantAvatar({ isLoading = false, isActive = false }: { isLoading?: boolean; isActive?: boolean }) {
584→  return (
585→    <Avatar
586→      className={cn(
587→        ASSISTANT_AVATAR_CLASSNAME,
588→        isActive && 'assistant-avatar--active border-primary/30 bg-primary/5 shadow-primary/20',
589→      )}
590→      style={{ transform: isLoading ? 'translateX(calc(-100% - 1rem))' : 'translateX(calc(-100% - 0.75rem))' }}
591→    >
592→      <AvatarFallback>
593→        <div className={cn('relative', isActive && 'assistant-avatar--pirate-sway')}>
594→          <Bot className={cn('h-4 w-4', isActive && 'text-primary/80')} />
595→        </div>
596→      </AvatarFallback>
597→    </Avatar>
598→  );
599→}
600→
601→export function MessageList({
602→  messages,
603→  isLoading,
604→  onAskUserSubmit,
605→  scrollRef,
606→  selectedDetailMessageId,
607→  selectedSubagentKey,
608→  onSelectToolDetail,
609→  onSelectSubagent,
610→}: MessageListProps) {
611→  const { blocks, lastVisibleMessage } = useMemo(() => {
612→    const visibleMessages = messages.filter(message => {
613→      if (message.event !== EVENT_TODO_UPDATE) {
614→        return true;
615→      }
616→
617→      return message.source?.kind === 'subagent';
618→    });
619→
620→    return {
621→      blocks: buildBlocks(visibleMessages),
622→      lastVisibleMessage: visibleMessages.at(-1),
623→    };
624→  }, [messages]);
625→
626→  const isLoadingAfterUser = isLoading && lastVisibleMessage?.role === 'user';
627→  const activeAssistantMessageId =
628→    isLoading && lastVisibleMessage?.role === 'assistant' ? lastVisibleMessage.id : undefined;
629→  // The last visible assistant message, used for subagent active detection
630→  const lastAssistantMessageId = lastVisibleMessage?.role === 'assistant' ? lastVisibleMessage.id : undefined;
631→  // streamingMessageId 必须指向最后一条正在接收内容的 assistant 消息，
632→  // 而不是最后一条可见消息（后者可能是 subagent 推送的 agent-end 等空消息），
633→  // 否则 markdown 渲染器会过早退出流式态，导致内容看起来被截断。
634→  const streamingMessageId = useMemo(() => {
635→    if (!isLoading) return undefined;
636→    // 只有当最后一条可见消息本身就是 main source 的 assistant 事件时，才标记为流式中。
637→    // 如果最新消息是 tool-call/agent-end 等，说明 assistant 文本块已经结束，
638→    // 不应再给旧的 assistant 消息设置 isAnimating=true，否则 markdown 渲染器会
639→    // 以不完整内容模式渲染，导致表格等 markdown 结构显示损坏。
640→    const last = lastVisibleMessage;
641→    if (last?.event === EVENT_ASSISTANT && (!last.source || last.source.kind === 'main')) {
642→      return last.id;
643→    }
644→    return undefined;
645→  }, [isLoading, lastVisibleMessage]);
646→
647→  return (
648→    <div className="mx-auto min-h-full max-w-3xl space-y-2 pb-4">
649→      {blocks.map((block, blockIndex) => {
650→        if (block.type === 'user') {
651→          return (
652→            <div key={block.message.id} className="relative">
653→              <UserAvatar />
654→              <div className="flex justify-end">
655→                <MessageItem
656→                  message={block.message}
657→                  isLoading={isLoading}
658→                  isStreaming={block.message.id === streamingMessageId}
659→                  onAskUserSubmit={onAskUserSubmit}
660→                />
661→              </div>
662→            </div>
663→          );
664→        }
665→
666→        const contentViews = buildAssistantContentViews(block.messages, streamingMessageId, activeAssistantMessageId);
667→        // Active if this block contains the last visible assistant message and we're still loading
668→        const isActiveAssistantBlock = Boolean(
669→          isLoading && lastAssistantMessageId && block.messages.some(message => message.id === lastAssistantMessageId),
670→        );
671→        const callbacks: MessageRenderCallbacks = {
672→          isLoading,
673→          selectedDetailMessageId,
674→          selectedSubagentKey,
675→          onAskUserSubmit,
676→          onSelectToolDetail,
677→          onSelectSubagent,
678→        };
679→
680→        return (
681→          <div key={`assistant-${blockIndex}`} className="relative">
682→            <AssistantAvatar isActive={isActiveAssistantBlock} />
683→            <div className="min-h-8 space-y-1">
684→              {contentViews.map(contentView =>
685→                contentView.type === 'subagent'
686→                  ? renderSubagentContentView(contentView, callbacks)
687→                  : renderMainContentView(contentView, streamingMessageId, callbacks),
688→              )}
689→            </div>
690→          </div>
691→        );
692→      })}
693→
694→      {isLoadingAfterUser && (
695→        <div className="relative">
696→          <AssistantAvatar isLoading isActive />
697→          <div className="min-h-8" />
698→        </div>
699→      )}
700→
701→      <div ref={scrollRef} />
702→    </div>
703→  );
704→}
